report_script:
frappe.query_reports["Report Purchase Invoice VS  Purchase Receipt"] = {
    onload: function(report) {
        report.columns.forEach(col => {
            if (col.label === "Linked to Purchase Receipt") {
                col.format = (value) => {
                    if (value === "Yes") {
                        return `<span style="color:green; font-weight:bold;">${value}</span>`;
                    } else if (value === "No") {
                        return `<span style="color:red; font-weight:bold;">${value}</span>`;
                    }
                    return value;
                };
            }
        });
    }
};
